#!/usr/bin/env python3
"""Modern climate data analysis script for Python 3."""

from __future__ import annotations

import configparser
from pathlib import Path

import pandas as pd


BASE_DIR = Path(__file__).resolve().parent
DEFAULT_DATA_PATH = BASE_DIR / "climate_analyzer" / "sample_data" / "climate_data.csv"
DEFAULT_CONFIG_PATH = BASE_DIR / "climate_analyzer" / "config.ini"


class ClimateAnalyzer:
    """Analyze climate station temperature data."""

    def __init__(self, data_path: Path = DEFAULT_DATA_PATH, config_path: Path = DEFAULT_CONFIG_PATH) -> None:
        self.data_path = Path(data_path)
        self.config_path = Path(config_path)
        self.config = configparser.ConfigParser()
        self.config.read(self.config_path, encoding="utf-8")

    def load_temperature_data(self) -> pd.DataFrame:
        """Load climate observations from CSV using UTF-8 encoding."""
        return pd.read_csv(
            self.data_path,
            encoding="utf-8",
            parse_dates=["date"],
        )

    def station_mean_temperatures(self) -> pd.Series:
        """Return mean temperature by station ID."""
        data = self.load_temperature_data()
        return data.groupby("station_id", sort=True)["temperature"].mean()

    def run_analysis(self) -> None:
        """Print each station's mean temperature."""
        for station_id, mean_temperature in self.station_mean_temperatures().items():
            print(f"Station {station_id} mean temperature: {mean_temperature:.1f}°C")


if __name__ == "__main__":
    ClimateAnalyzer().run_analysis()
